#include<bits/stdc++.h>
using namespace std;
int dp[1010][1010],a[1010][1010],v[1000010],now[1000010],cnt,n,m,k;
const int mod=1e9+7;
void dfs(int l,int r)
{
    if(l==r)
    {
        return;
    }
    int mid=(l+r)/2;
    dfs(l,mid);
    cnt++;
    int sum=0;
    for(int j=1;j<=m;j++)
    {
        for(int i=r;i>mid;i--)
        {
            if(now[a[i][j]]!=cnt)
            {
                now[a[i][j]]=cnt;
                v[a[i][j]]=0;
            }
            dp[i][j]=((((dp[i][j]+sum)%mod)-v[a[i][j]])%mod+mod)%mod;
        }
        for(int i=l;i<=mid;i++)
        {
            if(now[a[i][j]]!=cnt)
            {
                now[a[i][j]]=cnt;
                v[a[i][j]]=0;
            }
            sum=(sum+dp[i][j])%mod;
            v[a[i][j]]=(v[a[i][j]]+dp[i][j])%mod;
        }
    }
    dfs(mid+1,r);
}
int main()
{
    scanf("%d%d%d",&n,&m,&k);
    for(int i=1;i<=n;i++)
    {
        for(int j=1;j<=m;j++)
        {
            scanf("%d",&a[i][j]);
        }
    }
    dp[1][1]=1;
    dfs(1,n);
    printf("%d",dp[n][m]);
    return 0;
}
